proof fn phi_1_new_can_reject_valid(number_of_bits: usize, result: Result<Bitmap, Error>)
    requires
        // Input satisfies all validity conditions
        number_of_bits > 0,
        number_of_bits < u32::MAX as usize,
        number_of_bits % (u8::BITS as usize) == 0,
        // Bad scenario: result is Err despite valid input
        result is Err,
    ensures
        // All four ensures of new() are still satisfied
        result matches Ok(bitmap) ==> (bitmap.inv() && bitmap@.num_bits == number_of_bits as int && bitmap@.is_empty()),
        (number_of_bits == 0) ==> result is Err,
        (number_of_bits >= u32::MAX as usize) ==> result is Err,
        (number_of_bits % (u8::BITS as usize) != 0) ==> result is Err,
{
    // Ok branch is vacuously true (result is Err).
    // The three Err-forcing conditions all have false antecedents.
}

proof fn phi_2_alloc_range_rejects_with_free(pre: Bitmap, post: Bitmap, size: usize, result: Result<usize, Error>)
    requires
        // alloc_range preconditions
        pre.inv(),
        size > 0,
        size as int <= pre@.num_bits,
        // A contiguous free range of the requested size exists
        exists|s: int| 0 <= s && s + size as int <= pre@.num_bits
            && (forall|j: int| s <= j < s + size as int ==> !pre@.is_bit_set(j)),
        // Bad scenario: Err returned, state unchanged
        result is Err,
        post.inv(),
        post@.num_bits == pre@.num_bits,
        forall|i: int| 0 <= i < pre@.num_bits ==> (post@.is_bit_set(i) == pre@.is_bit_set(i)),
    ensures
        // All visible spec ensures hold
        post.inv(),
        result matches Ok(start) ==> (
            0 <= start && start < post@.num_bits
            && 0 < size as int && size as int <= post@.num_bits
            && start + size as int <= post@.num_bits
            && post@.num_bits == pre@.num_bits
        ),
{
    // Ok branch is vacuously true (result is Err).
    // Err branch lacks a 'no free range exists' postcondition.
}

